import{_ as e,o as a,c as i,ag as o}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Compatibility Scope","description":"","frontmatter":{},"headers":[],"relativePath":"development/compatibility.md","filePath":"development/compatibility.md","lastUpdated":1775719799000}'),r={name:"development/compatibility.md"};function s(d,t,n,c,l,p){return a(),i("div",null,[...t[0]||(t[0]=[o(`<h1 id="compatibility-scope" tabindex="-1">Compatibility Scope <a class="header-anchor" href="#compatibility-scope" aria-label="Permalink to &quot;Compatibility Scope&quot;">​</a></h1><p><strong>Last updated:</strong> 2026-03-22 <strong>Source docs consolidated:</strong> <code>docs/MATTERMOST_CLIENTS.md</code>, <code>docs/reference/compatibility-matrix.md</code></p><hr><h2 id="_1-compatibility-commitment" tabindex="-1">1. Compatibility Commitment <a class="header-anchor" href="#_1-compatibility-commitment" aria-label="Permalink to &quot;1. Compatibility Commitment&quot;">​</a></h2><p>rustchat commits to supporting Mattermost mobile (iOS/Android) and desktop clients as first-class external clients. Specifically:</p><ul><li>Mattermost Mobile v2.x clients can authenticate and use core functionality</li><li>Mattermost Desktop clients can connect via the <code>/api/v4/</code> HTTP surface</li><li>The Mattermost WebSocket protocol (<code>/api/v4/websocket</code>) is supported including auth challenge, session resumption, and standard event types</li></ul><p>This is not a full Mattermost clone — some advanced features (plugins, advanced search, custom emoji upload) are not implemented.</p><hr><h2 id="_2-current-coverage" tabindex="-1">2. Current Coverage <a class="header-anchor" href="#_2-current-coverage" aria-label="Permalink to &quot;2. Current Coverage&quot;">​</a></h2><h3 id="mobile-critical-endpoints-primary-metric" tabindex="-1">Mobile-critical endpoints (primary metric) <a class="header-anchor" href="#mobile-critical-endpoints-primary-metric" aria-label="Permalink to &quot;Mobile-critical endpoints (primary metric)&quot;">​</a></h3><p><strong>39/41 endpoints working (95.1%)</strong> — as of 2026-03-17</p><table tabindex="0"><thead><tr><th>Category</th><th>Coverage</th></tr></thead><tbody><tr><td>Authentication &amp; Session</td><td>6/6 ✅</td></tr><tr><td>User Management</td><td>5/5 ✅</td></tr><tr><td>Teams</td><td>4/4 ✅</td></tr><tr><td>Channels</td><td>6/6 ✅</td></tr><tr><td>Posts &amp; Messaging</td><td>7/7 ✅</td></tr><tr><td>Threads</td><td>3/3 ✅</td></tr><tr><td>Files</td><td>3/3 ✅</td></tr><tr><td>Preferences</td><td>2/2 ✅</td></tr><tr><td>WebSocket</td><td>1/1 ✅</td></tr><tr><td>System</td><td>2/2 ✅</td></tr><tr><td><strong>Total</strong></td><td><strong>39/41</strong></td></tr></tbody></table><p><strong>Known gaps (2/41):</strong></p><table tabindex="0"><thead><tr><th>Endpoint</th><th>Status</th><th>Impact</th><th>Planned</th></tr></thead><tbody><tr><td><code>POST /api/v4/emoji</code></td><td>❌ Not implemented</td><td>Medium — custom emoji upload unavailable</td><td>Phase 2</td></tr><tr><td><code>POST /api/v4/posts/search</code></td><td>❌ Not implemented</td><td>Medium — advanced search unavailable</td><td>Phase 2</td></tr></tbody></table><p>For the endpoint coverage summary, see <a href="./../reference/compatibility-matrix">Reference Compatibility Matrix</a>.</p><h3 id="full-v4-api-surface-secondary-metric" tabindex="-1">Full v4 API surface (secondary metric) <a class="header-anchor" href="#full-v4-api-surface-secondary-metric" aria-label="Permalink to &quot;Full v4 API surface (secondary metric)&quot;">​</a></h3><p>Historical full-surface analysis is available in archived compatibility notes and is intentionally broader than the mobile-critical metric. The gap is expected: rustchat does not aim to implement the full Mattermost v4 API, only the subset required for mobile and desktop client operation.</p><p>Do not conflate these two numbers. <strong>39/41 (95.1%)</strong> is the mobile compatibility headline. <strong>~60%</strong> is the broader full-API coverage figure.</p><hr><h2 id="_3-protected-surface" tabindex="-1">3. Protected Surface <a class="header-anchor" href="#_3-protected-surface" aria-label="Permalink to &quot;3. Protected Surface&quot;">​</a></h2><p>The following paths form the Mattermost compatibility surface. Changes here require compat-reviewer co-approval (<code>@zoorpha</code>) and are automatically elevated to the <code>elevated</code> risk tier per <code>.governance/protected-paths.yml</code>:</p><table tabindex="0"><thead><tr><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>backend/src/api/v4/</code></td><td>Mattermost HTTP API v4 handlers</td></tr><tr><td><code>backend/src/mattermost_compat/</code></td><td>Response transformation, field mapping utilities</td></tr><tr><td><code>backend/compat/</code></td><td>Contract JSON schemas + contract validation tests</td></tr><tr><td><code>backend/src/realtime/</code></td><td>WebSocket hub (v4 event contracts)</td></tr></tbody></table><p>No changes to these paths without compat review. If unsure whether your change touches this surface, treat it as if it does.</p><hr><h2 id="_4-contract-tests" tabindex="-1">4. Contract Tests <a class="header-anchor" href="#_4-contract-tests" aria-label="Permalink to &quot;4. Contract Tests&quot;">​</a></h2><p>Contract tests live in <code>backend/compat/tests/</code>. They validate that rustchat&#39;s API responses conform to the expected Mattermost v4 JSON schemas.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run contract tests (requires live Postgres + Redis)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backend</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RUSTCHAT_TEST_DATABASE_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">postgres://...</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> contract</span></span></code></pre></div><p>Contract JSON schemas: <code>backend/compat/</code> — one schema per major entity type (user, channel, post, error).</p><p>When the compat surface changes, update the schema and regenerate the contract test. Do not merge compat surface changes without passing contract tests.</p><hr><h2 id="_5-gap-handling" tabindex="-1">5. Gap Handling <a class="header-anchor" href="#_5-gap-handling" aria-label="Permalink to &quot;5. Gap Handling&quot;">​</a></h2><p>New gaps discovered during development:</p><ol><li>Open a GitHub issue using the <code>Bug Report</code> template, set <code>Compatibility impact: Yes — affects Mattermost clients</code></li><li>Label will be applied as <code>area/compat</code> during triage</li><li>Implementation planned via the standard spec → plan → execution workflow with compat-reviewer co-approval</li></ol><hr><h2 id="_6-connecting-mattermost-clients" tabindex="-1">6. Connecting Mattermost Clients <a class="header-anchor" href="#_6-connecting-mattermost-clients" aria-label="Permalink to &quot;6. Connecting Mattermost Clients&quot;">​</a></h2><p><strong>Server URL:</strong> <code>http://your-host:8080</code> (Nginx proxy, recommended) or <code>http://your-host:3000</code> (direct backend)</p><table tabindex="0"><thead><tr><th>Port</th><th>Service</th><th>Notes</th></tr></thead><tbody><tr><td>8080</td><td>Nginx proxy</td><td>Recommended — handles web UI and <code>/api/v4</code></td></tr><tr><td>3000</td><td>Backend direct</td><td>Bypass Nginx if needed</td></tr></tbody></table><p><strong>Steps:</strong></p><ol><li>In Mattermost Mobile or Desktop: Settings → Add Server</li><li>Enter the Server URL (port 8080)</li><li>Use email/password login (SSO configurable separately)</li><li>WebSocket connects automatically to <code>/api/v4/websocket</code></li></ol><p><strong>Known client limitations:</strong></p><ul><li>Push notifications require the push-proxy service to be running with valid FCM/APNS credentials</li><li>Some advanced features (search, custom emoji, plugins) are not available</li></ul>`,41)])])}const u=e(r,[["render",s]]);export{m as __pageData,u as default};
